function normalizePhone(p) {
  return p.replace(/\s/g, "").replace(/^0+/, "");
}

const phone = ref("")
const results = ref([])
const error = ref(false)
const loading = ref(false)

const handleSearch = () => {
  if (!phone.value.trim()) return
  loading.value = true
  error.value = false
  results.value = []

  setTimeout(() => {
    const input = normalizePhone(phone.value.trim())
    const found = members.filter(m => normalizePhone(m.phone) === input)
    if (found.length > 0) {
      results.value = found
    } else {
      error.value = true
    }
    loading.value = false
  }, 800)
}

const handleReset = () => {
  phone.value = ""
  results.value = []
  error.value = false
}
